Now i have my game working fine, i need to add more features to it, first of all, i have a menu.py file which contains code for diplaying a menu when the game launches, here is the code inside of it, please modify the main.py so it gets displayed, code : import pygame
from settings import *
from game import Game

class Menu:
    def __init__(self, screen):
        self.screen = screen
        self.running = True
        self.state = "main"
        self.clock = pygame.time.Clock()

    def draw_text(self, text, size, x, y, color=WHITE):
        font = pygame.font.Font(None, size)
        text_surface = font.render(text, True, color)
        text_rect = text_surface.get_rect(center=(x, y))
        self.screen.blit(text_surface, text_rect)

    def main_menu(self):
        self.draw_text("My Game Title", 64, SCREEN_WIDTH / 2, SCREEN_HEIGHT / 4, WHITE)
        self.draw_text("Developed by Me", 32, SCREEN_WIDTH / 2, SCREEN_HEIGHT / 4 + 50, GRAY)

    def options_menu(self):
        self.draw_text("Options", 64, SCREEN_WIDTH / 2, SCREEN_HEIGHT / 2, WHITE)

    def update(self):
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                self.running = False
                pygame.quit()
                exit()

        self.screen.fill(BLACK)

        if self.state == "main":
            self.main_menu()
        elif self.state == "options":
            self.options_menu()

        pygame.display.flip()
        self.clock.tick(60)

    def play_game(self):
        game_instance = Game(self.screen)
        game_instance.run()
        self.state = "main"  # Transition back to main menu after the game*
